import 'dart:convert'; import 'package:flutter/services.dart'; import '../../core/utils/geo_math.dart'; import '../../domain/models/grid_cell.dart'; import '../../domain/models/target_model.dart';
class LocalPackDatasource { List<GridCell> _cells=[]; List<TargetModel> _targets=[]; Future<void> load() async { final gridText=await rootBundle.loadString('assets/packs/red_sea_hills/grid_index.json'); final targetText=await rootBundle.loadString('assets/packs/red_sea_hills/targets_master.json'); _cells=(jsonDecode(gridText) as List).map((e)=>GridCell.fromJson(e)).toList(); _targets=(jsonDecode(targetText) as List).map((e)=>TargetModel.fromJson(e)).toList(); } List<GridCell> get cells=>_cells; List<TargetModel> get targets=>_targets; GridCell nearestCell(double lat,double lon){ if(_cells.isEmpty) throw StateError('Region pack is not loaded.'); var best=_cells.first; var bestD=GeoMath.distanceMeters(lat,lon,best.lat,best.lon); for(final c in _cells.skip(1)){ final d=GeoMath.distanceMeters(lat,lon,c.lat,c.lon); if(d<bestD){best=c; bestD=d;} } return best; }}
